  1→/**
  2→ * Event bridge: transforms Claude Agent SDK messages into Brain StreamEvent
  3→ * variants and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (transformSdkMessage) + effectful bridge handle
  6→ * (startEventBridge) that manages the event forwarding lifecycle.
  7→ */
  8→import type {
  9→  AgentTokenEvent,
 10→  AgentFileChangeEvent,
 11→  AgentStatusEvent,
 12→  StreamEvent,
 13→} from "../../shared/contracts";
 14→import type { StallDetectorHandle } from "./stall-detector";
 15→
 16→// ---------------------------------------------------------------------------
 17→// SDK message types (from @anthropic-ai/claude-code)
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ContentBlock =
 21→  | { type: "text"; text: string }
 22→  | { type: "tool_use"; id: string; name: string; input: Record<string, unknown> }
 23→  | { type: "tool_result"; tool_use_id: string; content: string };
 24→
 25→export type SdkMessage =
 26→  | { type: "assistant"; content: ContentBlock[] }
 27→  | { type: "result"; subtype: "success"; duration_ms: number }
 28→  | { type: "result"; subtype: "error"; error: string }
 29→  | { type: "user" };
 30→
 31→// ---------------------------------------------------------------------------
 32→// Port: dependencies as function signatures
 33→// ---------------------------------------------------------------------------
 34→
 35→export type EventBridgeDeps = {
 36→  emitEvent: (streamId: string, event: StreamEvent) => void;
 37→  updateLastEventAt: (sessionId: string) => Promise<void>;
 38→};
 39→
 40→// ---------------------------------------------------------------------------
 41→// Bridge handle
 42→// ---------------------------------------------------------------------------
 43→
 44→export type EventBridgeHandle = {
 45→  handleMessage: (message: SdkMessage) => void;
 46→  stop: () => void;
 47→};
 48→
 49→// ---------------------------------------------------------------------------
 50→// File operation tool detection
 51→// ---------------------------------------------------------------------------
 52→
 53→/** Tool names that represent file write/edit operations. */
 54→const FILE_WRITE_TOOLS = new Set(["Write"]);
 55→const FILE_EDIT_TOOLS = new Set(["Edit"]);
 56→
 57→function isFileOperationTool(toolName: string): boolean {
 58→  return FILE_WRITE_TOOLS.has(toolName) || FILE_EDIT_TOOLS.has(toolName);
 59→}
 60→
 61→function extractFileChangeType(toolName: string): AgentFileChangeEvent["changeType"] {
 62→  if (FILE_WRITE_TOOLS.has(toolName)) return "created";
 63→  if (FILE_EDIT_TOOLS.has(toolName)) return "modified";
 64→  return "modified";
 65→}
 66→
 67→function extractFilePath(input: Record<string, unknown>): string | undefined {
 68→  if (typeof input.file_path === "string") return input.file_path;
 69→  return undefined;
 70→}
 71→
 72→// ---------------------------------------------------------------------------
 73→// Pure transform: SDK message -> Brain StreamEvent[]
 74→// ---------------------------------------------------------------------------
 75→
 76→function transformTextBlock(
 77→  block: { type: "text"; text: string },
 78→  sessionId: string,
 79→): AgentTokenEvent {
 80→  return {
 81→    type: "agent_token",
 82→    sessionId,
 83→    token: block.text,
 84→  };
 85→}
 86→
 87→function transformToolUseBlock(
 88→  block: { type: "tool_use"; id: string; name: string; input: Record<string, unknown> },
 89→  sessionId: string,
 90→): AgentFileChangeEvent | undefined {
 91→  if (!isFileOperationTool(block.name)) return undefined;
 92→
 93→  const filePath = extractFilePath(block.input);
 94→  if (!filePath) return undefined;
 95→
 96→  return {
 97→    type: "agent_file_change",
 98→    sessionId,
 99→    file: filePath,
100→    changeType: extractFileChangeType(block.name),
101→  };
102→}
103→
104→function transformAssistantContent(
105→  content: ContentBlock[],
106→  sessionId: string,
107→): StreamEvent[] {
108→  const events: StreamEvent[] = [];
109→  for (const block of content) {
110→    if (block.type === "text") {
111→      events.push(transformTextBlock(block, sessionId));
112→    } else if (block.type === "tool_use") {
113→      const fileEvent = transformToolUseBlock(block, sessionId);
114→      if (fileEvent) events.push(fileEvent);
115→    }
116→  }
117→  return events;
118→}
119→
120→function transformResultMessage(
121→  message: { type: "result"; subtype: "success"; duration_ms: number } | { type: "result"; subtype: "error"; error: string },
122→  sessionId: string,
123→): AgentStatusEvent {
124→  if (message.subtype === "error") {
125→    return {
126→      type: "agent_status",
127→      sessionId,
128→      status: "error",
129→      error: message.error,
130→    };
131→  }
132→  return {
133→    type: "agent_status",
134→    sessionId,
135→    status: "completed",
136→  };
137→}
138→
139→export function transformSdkMessage(
140→  message: SdkMessage,
141→  sessionId: string,
142→): StreamEvent[] {
143→  switch (message.type) {
144→    case "assistant":
145→      return transformAssistantContent(message.content, sessionId);
146→
147→    case "result":
148→      return [transformResultMessage(message, sessionId)];
149→
150→    default:
151→      return [];
152→  }
153→}
154→
155→// ---------------------------------------------------------------------------
156→// Step event detection for stall detector
157→// ---------------------------------------------------------------------------
158→
159→/** Returns true if the message contains tool_use blocks for file operations. */
160→function containsFileOperationStep(message: SdkMessage): boolean {
161→  if (message.type !== "assistant") return false;
162→  return message.content.some(
163→    (block) => block.type === "tool_use" && isFileOperationTool(block.name),
164→  );
165→}
166→
167→// ---------------------------------------------------------------------------
168→// Bridge handle factory
169→// ---------------------------------------------------------------------------
170→
171→export function startEventBridge(
172→  deps: EventBridgeDeps,
173→  streamId: string,
174→  sessionId: string,
175→  stallDetector?: StallDetectorHandle,
176→): EventBridgeHandle {
177→  let stopped = false;
178→
179→  const handleMessage = (message: SdkMessage): void => {
180→    if (stopped) return;
181→
182→    const streamEvents = transformSdkMessage(message, sessionId);
183→    for (const streamEvent of streamEvents) {
184→      deps.emitEvent(streamId, streamEvent);
185→    }
186→
187→    // Fire-and-forget: update last_event_at for stall detection
188→    if (streamEvents.length > 0) {
189→      deps.updateLastEventAt(sessionId);
190→    }
191→
192→    // Notify stall detector of activity
193→    if (stallDetector && streamEvents.length > 0) {
